class Solution {
    public String countOfAtoms(String formula) {
        Map<String, Integer> count = new HashMap<>();
        Stack<Map<String, Integer>> stack = new Stack<>();
        stack.push(count);
        int i = 0;
        while (i < formula.length()) {
            if (formula.charAt(i) == '(') {
                count = new HashMap<>();
                stack.push(count);
                i++;
            } else if (formula.charAt(i) == ')') {
                i++;
                int j = i;
                while (i < formula.length() && Character.isDigit(formula.charAt(i))) {
                    i++;
                }
                int multiplier = j < i ? Integer.parseInt(formula.substring(j, i)) : 1;
                Map<String, Integer> top = stack.pop();
                count = stack.peek();
                for (Map.Entry<String, Integer> entry : top.entrySet()) {
                    count.put(entry.getKey(), count.getOrDefault(entry.getKey(), 0) + entry.getValue() * multiplier);
                }
            } else {
                int j = i + 1;
                while (j < formula.length() && Character.isLowerCase(formula.charAt(j))) {
                    j++;
                }
                String name = formula.substring(i, j);
                i = j;
                int k = i;
                while (i < formula.length() && Character.isDigit(formula.charAt(i))) {
                    i++;
                }
                int num = k < i ? Integer.parseInt(formula.substring(k, i)) : 1;
                count.put(name, count.getOrDefault(name, 0) + num);
            }
        }
        List<String> result = new ArrayList<>();
        for (String name : count.keySet().stream().sorted().toArray(String[]::new)) {
            result.add(name);
            if (count.get(name) > 1) {
                result.add(String.valueOf(count.get(name)));
            }
        }
        return String.join("", result);
    }
}
